using Bodoconsult.App.Abstractions.Extensions;
using IpCommunicationSample.Common.BusinessTransactions.Requests;
using IpBackend.Bll.BusinessLogic.Adapters;

namespace IpCommunicationSampleTests.Backend.Adapter;

[TestFixture]
internal class TncpIpDeviceTcpIpBusinessLogicAdapterTests
{
    [Test]
    public void GetPaths_Channels1And3_ReturnsArray()
    {
        // Arrange 
        var request = new StartMessagingBusinessTransactionRequestData()
        {
            Snapshot = true,
            Channel1 = true,
            Channel3 = true
        };

        // Act  
        var result = TncpIpDeviceTcpIpBusinessLogicAdapter.GetPaths(request);

        // Assert
        Assert.That(result, Is.EqualTo("1,3"));
    }

    [Test]
    public void GetPaths_AllChannels_ReturnsArray()
    {
        // Arrange 
        var request = new StartMessagingBusinessTransactionRequestData()
        {
            Snapshot = true,
            Channel1 = true,
            Channel3 = true,
            Channel2 = true,
            Channel4 = true
        };

        // Act  
        var result = TncpIpDeviceTcpIpBusinessLogicAdapter.GetPaths(request);

        // Assert
        Assert.That(result, Is.EqualTo("1,2,3,4"));
    }

    [Test]
    public void GetConfig_ValidConfig_ReturnsArray()
    {
        // Arrange 
        const string cmd = "<CONFIG>0x00x10x20x30xC0xF";

        var expectedResult = new byte[] { 0x0, 0x1, 0x2, 0x3, 0xC, 0xF };

        // Act  
        var result = TncpIpDeviceTcpIpBusinessLogicAdapter.GetConfig(cmd);

        // Assert
        Assert.That(result.IsEqualTo(expectedResult), Is.True);
    }

    [Test]
    public void GetConfig_ValidConfigRealWorld1_ReturnsArray()
    {
        // Arrange 
        const string cmd = "<CONFIG>";

        var expectedResult = new byte[254];
        expectedResult[252] = 0xc;
        expectedResult[253] = 0xf;

        // Act  
        var result = TncpIpDeviceTcpIpBusinessLogicAdapter.GetConfig(cmd);

        // Assert
        using (Assert.EnterMultipleScope())
        {
            Assert.That(result.IsEqualTo(expectedResult), Is.True);
            Assert.That(result[0], Is.Zero);
            Assert.That(result[1], Is.Zero);

            Assert.That(result[253], Is.EqualTo(0xf));
            Assert.That(result[252], Is.EqualTo(0xc));
        }
    }

    [Test]
    public void GetConfig_ValidConfigRealWorld2_ReturnsArray()
    {
        // Arrange 
        const string cmd = "<CONFIG>";

        var expectedResult = new byte[256];
        expectedResult[254] = 0xc;
        expectedResult[255] = 0xf;

        // Act  
        var result = TncpIpDeviceTcpIpBusinessLogicAdapter.GetConfig(cmd);

        // Assert
        using (Assert.EnterMultipleScope())
        {
            Assert.That(result.IsEqualTo(expectedResult), Is.True);
            Assert.That(result[0], Is.Zero);
            Assert.That(result[1], Is.Zero);

            Assert.That(result[255], Is.EqualTo(0xf));
            Assert.That(result[254], Is.EqualTo(0xc));
        }
    }

    [Test]
    public void GetConfig_ValidConfigRealWorld3_ReturnsArray()
    {
        // Arrange 
        const string cmd =
            "<CONFIG>";

        var expectedResult = new byte[256];
        expectedResult[254] = 0xc;
        expectedResult[255] = 0xf;

        // Act  
        var result = TncpIpDeviceTcpIpBusinessLogicAdapter.GetConfig(cmd);

        // Assert
        using (Assert.EnterMultipleScope())
        {
            Assert.That(result.IsEqualTo(expectedResult), Is.True);
            Assert.That(result[0], Is.Zero);
            Assert.That(result[1], Is.Zero);

            Assert.That(result[255], Is.EqualTo(0xf));
            Assert.That(result[254], Is.EqualTo(0xc));
        }
    }
}